// Script Continued Below
var Template_uiAction = Class.create();
Template_uiAction.prototype = {
    initialize: function() {
    },

	uiAction_ActivateTemplateTask: function(templateTask) {
		templateTask.active = true;
		templateTask.update();
	},

	uiAction_DeactivateTemplateTask: function(templateTask) {
		templateTask.active = false;
		templateTask.update();
	},

	uiAction_DisableSharedAttachmentsTemplateTask: function(templateTask) {
		var grProcessTemplte = new GlideRecordSecure("x_153465_discovert_discover_routing_template");
		if(grProcessTemplte.get(templateTask.tasker_process_definition)){
			grProcessTemplte.u_shared_attachments = false;
			grProcessTemplte.update();
		}
	},

	uiAction_DisableSharedDocumentsTemplateTask: function(templateTask) {
		var grProcessTemplte = new GlideRecordSecure("x_153465_discovert_discover_routing_template");
		if(grProcessTemplte.get(templateTask.tasker_process_definition)){
			grProcessTemplte.u_shared_documents = false;
			grProcessTemplte.update();
		}		
	},

	uiAction_EnableSharedAttachmentsTemplateTask: function(templateTask) {
		var grProcessTemplte = new GlideRecordSecure("x_153465_discovert_discover_routing_template");
		if(grProcessTemplte.get(templateTask.tasker_process_definition)){
			grProcessTemplte.u_shared_attachments = true;
			grProcessTemplte.update();
		}
	},

	uiAction_EnableSharedDocumentsTemplateTask: function(templateTask) {
		var grProcessTemplte = new GlideRecordSecure("x_153465_discovert_discover_routing_template");
		if(grProcessTemplte.get(templateTask.tasker_process_definition)){
			grProcessTemplte.u_shared_documents = true;
			grProcessTemplte.update();
		}
	},

	uiAction_SaveTemplateTask: function(templateTask) {
		templateTask.insert();
	},

	uiAction_ActivateTemplate: function(template) {
		template.u_active = true;
		template.update();
	},

	uiAction_CreateTemplate: function(template) {
		var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
		gr.addQuery('template_name', template.template_name);
		gr.addQuery('process_level', template.process_level);

		if(template.process_level == 'ou_process')
			gr.addQuery('process_ou', template.process_ou);

		gr.query();

		if(gr.next()){
			// TODO - multilanguage
			gs.addErrorMessage("The name '" + template.template_name + "' is already being used.  Please change the Template Name to a unique name");
		}else{
			template.insert();
			// TODO - multilanguage
			gs.addInfoMessage("Template <b>" + template.template_name  + '</b> has been created. <a href="../discovertaskerportal?id=discovertasker_processtemplatedetails&table=x_153465_discovert_route_tasks&sys_id='+template.parent_task_def+'">Click here to build it</a>');
		}
	},

	uiAction_DeactivateTemplate: function(template) {
		template.u_active = false;
		template.update();
	},

	uiAction_DisableSharedAttachmentsTemplate: function(template) {
		template.u_shared_attachments = false;
		template.update();
	},

	uiAction_DisableSharedDocumentsTemplate: function(template) {
		template.u_shared_documents = false;
		template.update();
	},

	uiAction_EnableSharedAttachmentsTemplate: function(template) {
		template.u_shared_attachments = true;
		template.update();
	},

	uiAction_EnableSharedDocumentsTemplate: function(template) {
		template.u_shared_documents = true;
		template.update();		
	},

	uiAction_StartTemplateInstance: function(templateInstance) {
		var tTH = new TaskTemplateHelpers();
		var fields = tTH.createEmptyTemplateFieldsJSON();
		for(var field in fields){
			fields[field].value = templateInstance.getValue(field);
		}

		var templateInputs = {};
		templateInputs = tTH.loadTemplateInputsFromDataFields(fields);	
		tTH.startTemplateWithID(templateInstance.routing_template_ref, true, templateInputs);
	},

	uiAction_CreateSchedule: function(schedule) {
		if(!schedule.tasker_process.nil())
		{
			schedule.insert();
			// TODO - multilanguage
			gs.addInfoMessage('Template schedule <b>' + schedule.name + '</b> has been created');
		}
		else {
			schedule.setAbortAction(true);
			// TODO - multilanguage
			gs.addErrorMessage('Template cannot be empty');
		}		
	},

	uiAction_DeleteSchedule: function(schedule) {
		schedule.deleteRecord();
	},

	type: 'Template_uiAction'
};
